    {"text": "Chớ thấy sóng cả mà ngã tay chèo.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Trước khó khăn lớn, đừng bỏ cuộc — giữ vững ý chí và tiếp tục nỗ lực mới là con đường đến thành công."},
    {"text": "Có công mài sắt, có ngày nên kim.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Kiên trì mài giũa dù việc nhỏ nhất — mọi thành tựu đều đến từ nỗ lực bền bỉ theo thời gian."},
    {"text": "Đường dài mới biết ngựa hay, ở lâu mới biết người ngay kẻ tà.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Phẩm chất thật sự chỉ được bộc lộ qua thời gian và thử thách — đừng vội đánh giá người hay việc."},
    {"text": "Biết thì thưa thốt, không biết thì dựa cột mà nghe.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Khiêm tốn lắng nghe khi chưa hiểu rõ — sự khiêm tốn là khởi đầu của mọi sự học hỏi thật sự."},
    {"text": "Nhà sạch thì mát, bát sạch ngon cơm.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Trật tự và sự ngăn nắp tạo ra môi trường để làm việc hiệu quả và cuộc sống chất lượng hơn."},
