    {"text": "Bàn tay ta làm nên tất cả, có sức người sỏi đá cũng thành cơm.", "author": "Ca dao Việt Nam", "vi": None, "explain": "Lao động chân chính là nguồn gốc của mọi thành quả — bằng sức mình, con người có thể vượt qua mọi nghịch cảnh."},
    {"text": "Ăn quả nhớ kẻ trồng cây.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Luôn ghi nhớ và biết ơn những người đã tạo ra thành quả mà ta đang được hưởng."},
    {"text": "Thời gian là vàng bạc.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Thời gian là tài sản quý nhất — một khi đã qua đi, không thể lấy lại, hãy sử dụng từng giây phút có ý nghĩa."},
    {"text": "Chữ tâm kia mới bằng ba chữ tài.", "author": "Nguyễn Du", "vi": None, "explain": "Đức hạnh và tấm lòng tốt có giá trị hơn cả tài năng — người thành công thật sự phải có cả tâm lẫn tài."},
    {"text": "Người ta là hoa đất.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Con người là tạo vật quý giá nhất — mỗi người đều mang trong mình giá trị và tiềm năng độc đáo."},
    {"text": "Sóng cả không lo, sóng lớn không sợ.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Người có bản lĩnh không bị dao động trước khó khăn — sự bình thản và dũng cảm là sức mạnh thật sự."},
    {"text": "Mưu sự tại nhân, thành sự tại thiên.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Hãy hết lòng nỗ lực và lên kế hoạch chu đáo — còn kết quả cuối cùng tùy thuộc vào nhiều yếu tố khách quan."},
    {"text": "Một câu nhịn là chín câu lành.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Biết kiềm chế và nhường nhịn trong lúc bực bội sẽ giữ được hòa khí và tránh hối hận về sau."},
    {"text": "Gieo gió gặt bão.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Mọi hành động đều có hệ quả — làm điều tốt sẽ nhận lại điều tốt, làm điều xấu sẽ gánh chịu hậu quả."},
    {"text": "Khó mà không khổ, khổ mà không khó.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Nghèo khó về vật chất không đồng nghĩa với khổ sở tinh thần — thái độ sống tích cực mới quyết định hạnh phúc."},
    {"text": "Đi hỏi già, về nhà hỏi trẻ.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Người lớn tuổi có kinh nghiệm về thế giới bên ngoài, trẻ em có con mắt trong sáng về những gì gần gũi — mỗi người đều có điều để dạy ta."},
    {"text": "Lời nói chẳng mất tiền mua, lựa lời mà nói cho vừa lòng nhau.", "author": "Ca dao Việt Nam", "vi": None, "explain": "Ngôn từ có sức mạnh lớn — một lời nói khéo léo, chân thành có thể xây dựng mối quan hệ tốt đẹp mà không tốn gì."},
    {"text": "Trong gian khổ mới thấy được người anh hùng.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Phẩm chất thật sự của con người chỉ được bộc lộ khi đối mặt với nghịch cảnh và thử thách lớn."},
    {"text": "Cái khó ló cái khôn.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Áp lực và khó khăn buộc ta phải sáng tạo và tìm ra giải pháp mới — nghịch cảnh là bà đỡ của sự đổi mới."},
    {"text": "Học thầy không tày học bạn.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Học từ bạn bè đồng trang lứa đôi khi hiệu quả hơn — sự trao đổi ngang hàng mang lại góc nhìn thực tiễn và gần gũi."},
