    {"text": "Tốt gỗ hơn tốt nước sơn.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Chất lượng bên trong quan trọng hơn vẻ bề ngoài — hãy đầu tư vào năng lực thật sự thay vì hình thức."},
    {"text": "Nước chảy đá mòn.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Sự kiên trì bền bỉ cuối cùng sẽ thắng mọi trở ngại — dù khó khăn đến đâu, nỗ lực liên tục sẽ tạo ra thay đổi."},
    {"text": "Biết người biết ta, trăm trận trăm thắng.", "author": "Tôn Tử", "vi": None, "explain": "Hiểu rõ bản thân và đối tác/đối thủ là nền tảng của mọi quyết định sáng suốt trong công việc lẫn cuộc sống."},
    {"text": "Nhân bất học bất tri lý.", "author": "Tam Tự Kinh (Trung Quốc)", "vi": "Người không học thì không biết lẽ phải.", "explain": "Học vấn là nền tảng để hiểu đúng sai, phân biệt điều tốt xấu và sống có trách nhiệm."},
