    {"text": "Lá lành đùm lá rách.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Giúp đỡ người khó khăn hơn mình là đức tính cao đẹp — sự đoàn kết và lòng nhân ái làm cho xã hội vững mạnh."},
    {"text": "Trông người lại ngẫm đến ta.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Quan sát người khác để soi lại bản thân — thấy điều tốt thì học, thấy điều xấu thì tránh."},
    {"text": "Đã trót nhúng chàm thì phải giặt cho sạch.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Khi đã mắc sai lầm, hãy dũng cảm nhận trách nhiệm và sửa chữa — đó là biểu hiện của nhân cách trưởng thành."},
    {"text": "Cứng quá thì gãy, mềm quá thì uốn.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Sự linh hoạt và cân bằng là chìa khóa — biết khi nào cứng rắn, khi nào nhường nhịn mới là trí khôn."},
    {"text": "Người đẹp vì lụa, lúa tốt vì phân.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Môi trường, điều kiện và sự đầu tư đúng chỗ có thể giúp bất kỳ ai phát huy tối đa tiềm năng của mình."},
    {"text": "Hay làm thì giàu, hay chơi thì nghèo.", "author": "Tục ngữ Việt Nam", "vi": None, "explain": "Siêng năng lao động là con đường bền vững đến thịnh vượng — không có thành công nào đến mà không có nỗ lực."},
